// freq table, greedy
class Solution {
public:
    int minCost(vector<int>& nums1, vector<int>& nums2) {
        unordered_map<int, int> cnt;
        for (const auto& x : nums1) {
            ++cnt[x];
        }
        for (const auto& x : nums2) {
            --cnt[x];
        }
        int result = 0;
        for (const auto& [_, c] : cnt) {
            if (c % 2) {
                return -1;
            }
            if (c / 2 > 0) {
                result += c / 2;
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(n)

import collections


# freq table, greedy
class Solution(object):
    def minCost(self, nums1, nums2):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :rtype: int
        """
        cnt = collections.defaultdict(int)
        for x in nums1:
            cnt[x] += 1
        for x in nums2:
            cnt[x] -= 1
        result = 0
        for c in cnt.itervalues():
            if c%2:
                return -1
            if c//2 > 0:
                result += c//2 
        return result
